PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, display_name TEXT NOT NULL, points INTEGER NOT NULL DEFAULT 100, created_at TEXT NOT NULL DEFAULT (datetime ('now')));
CREATE TABLE IF NOT EXISTS matches (id INTEGER PRIMARY KEY, "group" TEXT, team1 TEXT NOT NULL, team2 TEXT NOT NULL, match_date TEXT, venue TEXT, status TEXT NOT NULL DEFAULT 'upcoming', result TEXT);
CREATE TABLE IF NOT EXISTS bets (id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL, match_id INTEGER NOT NULL, bet_choice TEXT NOT NULL, points_wagered INTEGER NOT NULL, created_at TEXT NOT NULL DEFAULT (datetime ('now')), UNIQUE (user_id, match_id), FOREIGN KEY (user_id) REFERENCES users (id), FOREIGN KEY (match_id) REFERENCES matches (id));
CREATE TABLE IF NOT EXISTS payouts (id INTEGER PRIMARY KEY AUTOINCREMENT, bet_id INTEGER NOT NULL, points_awarded INTEGER NOT NULL, settled_at TEXT NOT NULL DEFAULT (datetime ('now')), FOREIGN KEY (bet_id) REFERENCES bets (id));
DELETE FROM sqlite_sequence;
COMMIT;
